SELECT event_id, date_range, location, magnitude
FROM volcanic_events
WHERE CAST(SUBSTR(date_range, INSTR(date_range, ' ') + 1) AS INTEGER) > 2000;

SELECT date_range, depth, duration 
FROM volcanic_events 
WHERE status = 'ongoing' AND deep_volcanic > 0;

SELECT ve.location, ve.magnitude
FROM volcanic_events ve
WHERE ve.magnitude > (
  SELECT AVG(magnitude)
  FROM volcanic_events
);

SELECT COUNT(event_id) AS number_of_events, type_id 
FROM volcanic_events 
GROUP BY type_id;

SELECT ve.*, en.note
FROM volcanic_events ve
JOIN event_notes en ON ve.event_id = en.event_id;

SELECT event_id, user_id, access_date, access_type, access_ip, access_action
FROM event_access
WHERE (access_type = 'view' OR access_type = 'edit') AND access_ip = '192.168.0.1';

SELECT event_id, location 
FROM volcanic_events 
WHERE magnitude > (SELECT AVG(magnitude) FROM volcanic_events);

SELECT u.user_name, ea.event_id 
FROM users u 
JOIN event_access ea ON u.user_id = ea.user_id;

SELECT type_name, description, severity_level
FROM event_types
ORDER BY severity_level DESC;

SELECT magnitude, depth
FROM volcanic_events
WHERE event_id = 1;

SELECT ve.event_id, ve.location, ec.category_name
FROM volcanic_events ve
JOIN event_categories ec ON ve.category_id = ec.category_id;
